head.script:
//-------------------------------------------------------------------------
// 화면 로딩
//-------------------------------------------------------------------------
scwin.onpageload = async function() {
    scwin.parentFrame = $c.win.getParent();
    scwin.strCtrtNo = scwin.parentFrame.scwin.ctrtNo;

    //공통코드 조회
    const codeOptions = [
        { grpCd : "ZZ006", compID : "gr_tariff:crcCd" }
    ];
    $c.data.setCommonCode(codeOptions, function() {
        // ds_tariff 조회 후 통화 컬럼 매핑이 정상적으로 되지 않아,
        // 통화코드 조회 완료 후 메인 프로세스 실행
        $c.sbm.execute(sbm_eqNrmCd);
    });

    const comboOptions = [
        {
            method : "getGridCombo", 
            param1 : "EquipmentEBC", 
            param2 : "retrieveLogisticsEquipmentClss",
            param3 : ["ZZ210","ZZ202","ZZ201","LH"],
            param4 : true,
            compID : "gr_tariff:eqKndCd" 
        }
    ];

    $c.data.setGauceUtil(comboOptions);
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    if (scwin.parentFrame.wfm_ctrtComplete.getWindow().ds_completeYn.getCellData(0, "code") === "02") {
        $c.gus.cfDisableObjects([btn_save, btn_add, btn_del, btn_cls ]);
	}
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = async function() {
	console.log("scwin.f_retrieve");

    if($c.data.isModified(ds_tariff)) {
        let conf = await $c.win.confirm(MSG_CM_CRM_015);
        if(conf) {
			if(!scwin.parentFrame.scwin.f_isCompletedChk(1)) return false;
			await scwin.f_Save("");
		}
	}

    dma_search.set("ctrtNo", scwin.strCtrtNo);
    dma_search.set("selpchItemCd", "0003");
    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(moveGb, callback) {
    if(!$c.data.isModified(ds_tariff)) {
		$c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("하역-장비사용료"));
		return false;
    }else{
    	if(await scwin.f_reqFieldChk()) {
    		if(moveGb == "") {
                let conf = await $c.win.confirm(MSG_CM_CRM_001);
	    		if(conf) {
                    const e = await $c.sbm.execute(sbm_save);
					scwin.sbm_save_submitdone(e);
					return true;
				}else {
					return false;
				}
			}else {
				// tab 전환 시에 저장여부 확인 (04b 에서 넘어온 저장플래그)
                const e = await $c.sbm.execute(sbm_save);
				await scwin.sbm_save_submitdone(e, callback);
                return true;
			}
	    }else {
	    	return false;
	    }
    }
}

//-------------------------------------------------------------------------
// 필수 항목 확인
//-------------------------------------------------------------------------
scwin.f_reqFieldChk = async function() {
    let chkVal = await $c.gus.cfValidate([gr_tariff], null, 2);
	if(!chkVal)    return false;

	var min_amt;
	var max_amt;

	for (var i=0; i < ds_tariff.getTotalRow(); i++) {
		for(var j=0; j < ds_eqNrmCd.getTotalRow(); j++) {
			if(ds_tariff.getCellData(i, "minEqNrmCd") == ds_eqNrmCd.getCellData(j, "cd")) {
				min_amt = ds_eqNrmCd.getCellData(j, "amt");
			}

			if(ds_tariff.getCellData(i, "maxEqNrmCd") == ds_eqNrmCd.getCellData(j, "cd")) {
				max_amt = ds_eqNrmCd.getCellData(j, "amt");
			}
		}

		if (min_amt > max_amt) {
			$c.win.alert("최소장비규격이 최대장비규격보다 클 수 없습니다. 다시 확인 바랍니다.");
            gr_tariff.setFocusedCell(i, "minEqNrmCd");
			return false;
		}

		if (ds_tariff.getCellData(i, "aexpYn") == 0 && ds_tariff.getCellData(i, "ctrtTrf") == 0) {
			$c.win.alert("요율은 필수 입력 항목입니다.");
            gr_tariff.setFocusedCell(i, "ctrtTrf");
			return false;
		}

		if (ds_tariff.getCellData(i, "eqKndCd") != "" && (ds_tariff.getCellData(i, "minEqNrmCd") == "" || ds_tariff.getCellData(i, "maxEqNrmCd") == "")) {
			$c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("최소장비규격과 최대장비규격"));
            gr_tariff.setFocusedCell(i, "minEqNrmCd");
			return false;
		}
	}

	return true;
}

//-------------------------------------------------------------------------
// 규격 최소, 최대 필터
//-------------------------------------------------------------------------
scwin.f_filter = function() {
    var v_eqKndCd = ds_tariff.getCellData(ds_tariff.getRowPosition(), "eqKndCd");
    let condition = "upperCd=='" + v_eqKndCd + "'";
    ds_eqNrmCd.removeColumnFilterAll();
    $c.data.dataListFilter(ds_eqNrmCd, condition);
}

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_addRow = function() {
    console.log("scwin.f_addRow");
    let rowCnt = ds_tariff.getTotalRow();
	if (rowCnt == 0) {
		ds_tariff.insertRow(0);
		ds_tariff.setCellData(0, "ctrtNo", scwin.strCtrtNo);
        ds_tariff.setCellData(0, "transMdCtrtTrfSeq", "1");
		ds_tariff.setCellData(0, "selpchItemCd", "0003");
		ds_tariff.setCellData(0, "crcCd", "KRW");
	} else {
        ds_tariff.setRowJSON(rowCnt, ds_tariff.getRowJSON(ds_tariff.getRowPosition()));
	}

    gr_tariff.setFocusedCell(rowCnt, "eqKndCd");
    //scwin.f_filter();
}

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_delRow = function() {
    const rowIndex = gr_tariff.getFocusedRowIndex();

    if (gr_tariff.getFocusedRowStatus() === "C") {
        ds_tariff.removeRow(rowIndex);

        var totalRow = ds_tariff.getTotalRow(); 

        // 포커스 이동 판단
        if (totalRow === 0) {
            return;
        } else {
            var newIdx;
            if (rowIndex === 0) {
                // 삭제한 행이 첫 번째(0번)였던 경우: 현재의 0번(기존의 1번)에 포커스
                newIdx = 0;
            } else {
                // 일반적인 경우: 바로 위 행(rowIdx - 1)으로 이동
                newIdx = rowIndex - 1;
            }
            // 포커스 이동
            gr_tariff.setFocusedCell(newIdx, "");
        }
    } else {
        ds_tariff.deleteRow(rowIndex);
        gr_tariff.setFocusedCell(rowIndex, "");
    }
}


//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_cancelRow = function() {
    const rowIndex = gr_tariff.getFocusedRowIndex();

    if (gr_tariff.getFocusedRowStatus() === "C") {
        ds_tariff.removeRow(rowIndex);

        var totalRow = ds_tariff.getTotalRow(); 

        // 포커스 이동 판단
        if (totalRow === 0) {
            return;
        } else {
            var newIdx;
            if (rowIndex === 0) {
                // 삭제한 행이 첫 번째(0번)였던 경우: 현재의 0번(기존의 1번)에 포커스
                newIdx = 0;
            } else {
                // 일반적인 경우: 바로 위 행(rowIdx - 1)으로 이동
                newIdx = rowIndex - 1;
            }
            // 포커스 이동
            gr_tariff.setFocusedCell(newIdx, "");
        }
    } else {
        ds_tariff.undoRow(rowIndex);
        gr_tariff.setFocusedCell(rowIndex, "");
    }
}

//-------------------------------------------------------------------------
// 공통 팝업 호출
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(rowIndex, columnIndex, pWinCloseTF) {
    let columnId = gr_tariff.getColumnID(columnIndex);
    //let nmVal = value;

    switch (columnId) {
		case "commNm":
            //if($c.util.isEmpty(value)) nmVal = ds_tariff.getCellData(rowIndex, "commNm");
            udc_comCode.setSelectId("retrieveCommInfo");
            udc_comCode.cfCommonPopUp( scwin.callBackComm
                                     , ""
                                     , ds_tariff.getCellData(rowIndex, "commNm")
                                     , pWinCloseTF
                                     , "3"
                                     , "품목／품명코드,품목／품명,구분"
                                     , "120,170,70"
                                     , "4,5,6,7,8,9,10"
                                     , "2,4,,," +  ""
                                     , null
                                     , null
                                     , null
                                     , null
                                     , null
                                     , "F"
                                     , "품목／품명,품목／품명코드,품목／품명");
			break;

		case "lobranNm":
            //readonly일 때 팝업 호출 X
            if(gr_tariff.getCellReadOnly(rowIndex, columnId))   return;

            //if($c.util.isEmpty(value)) nmVal = ds_tariff.getCellData(rowIndex, "lobranNm");
            udc_comCode.setSelectId("retrieveLogisDeptInfo");
            udc_comCode.cfCommonPopUp( scwin.callBackDept
                                     , ""
                                     , ds_tariff.getCellData(rowIndex, "lobranNm")
                                     , pWinCloseTF
                                     , "7"
                                     , "작업점소코드,작업점소명"
                                     , "150,170"
                                     , null
                                     , "A,B"
                                     , null
                                     , null
                                     , null
                                     , null
                                     , null
                                     , "F"
                                     , "작업점소,작업점소코드,작업점소명");
			break;

		case "unitCd":  //단위
            udc_comCode.setSelectId("retrieveCommCdInfo");
            udc_comCode.cfCommonPopUp( scwin.callBackUnitCd
                                     , ds_tariff.getCellData(rowIndex, "unitCd")
                                     , ""
                                     , pWinCloseTF
                                     , "7"
                                     , null
                                     , "150,170"
                                     , null
                                     , "LO102,,"
                                     , null
                                     , null
                                     , null
                                     , null
                                     , null
                                     , "F"
                                     , null);
			break;	

		default:
			break;
	}

    scwin.pWinCloseTF = "";
}

//-------------------------------------------------------------------------
// 공통팝업호출 callBack
//-------------------------------------------------------------------------
//품목/품명
scwin.callBackComm = function(rtnList) {
    $c.gus.cfSetGridReturnValue(rtnList, ds_tariff, ds_tariff.getRowPosition(), "commCd", "commNm");
}

//작업점소
scwin.callBackDept = function(rtnList) {
    $c.gus.cfSetGridReturnValue(rtnList, ds_tariff, ds_tariff.getRowPosition(), "lobranCd", "lobranNm");
}

//단위
scwin.callBackUnitCd = function(rtnList) {
    if(rtnList != null && rtnList[0] != "N/A") {
        ds_tariff.setCellData(ds_tariff.getRowPosition(), "unitCd", rtnList[0]);
    } else {
        ds_tariff.setCellData(ds_tariff.getRowPosition(), "unitCd", "");
    }
}

/* ----------------------------------------------------------------------------
  T R A N S A C T I O N   C O M P O N E N T S   D E C L A R A T I O N
------------------------------------------------------------------------------*/
//코드 조회 완료 
scwin.sbm_eqNrmCd_submitdone = function(e) {
    console.log("scwin.sbm_eqNrmCd_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    for(var i=0; i<ds_eqNrmCd.getTotalRow(); i++) {
        ds_eqNrmCd.setCellData(i, "cdNm", "["+ds_eqNrmCd.getCellData(i, "cd")+"] "+ds_eqNrmCd.getCellData(i, "cdNm"));
    }

    scwin.f_retrieve();
}

//조회 완료
scwin.sbm_retrieve_submitdone = function(e) {
    console.log("scwin.sbm_retrieve_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    let rowCnt = ds_tariff.getTotalRow();
    spn_totalRow.setValue(rowCnt);

    if(rowCnt > 0) {
        gr_tariff.setFocusedCell(0, 0);
    }
}

//저장 완료
scwin.sbm_save_submitdone = async function (e, callback) {
    console.log("scwin.sbm_save_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    ds_tariff.initRowStatus();

    scwin.f_retrieve();

	if (typeof callback === "function") {
		callback();
	}
};

/* ----------------------------------------------------------------------------
  C O M P O N E N T' S   E V E N T S  
-----------------------------------------------------------------------------*/
//그리드 textImage 클릭 > 그리드 공통 팝업 호출
scwin.gr_tariff_ontextimageclick = function (rowIndex, columnIndex) {
    scwin.pWinCloseTF = "F";
    scwin.gr_tariff_onviewchange();
};

scwin.gr_tariff_onviewchange = function (info) {
    debugger;
    let rowIndex = ds_tariff.getRowPosition();
    let colId = gr_tariff.getFocusedColumnID();

    if(colId == "eqKndCd") {
        // scwin.f_filter();
    } else if(colId == "commNm" || colId == "unitCd" || colId == "lobranNm" ) {
        let pWinCloseTF = $c.util.isEmpty(scwin.pWinCloseTF)? "T" : "F";
        if(pWinCloseTF == "T" && $c.util.isEmpty(ds_tariff.getCellData(rowIndex, colId))) return;

        scwin.f_openCommonPopUp(rowIndex, colId, pWinCloseTF);
    }
};

//그리드 셀 선택 > 편집 설정
scwin.gr_tariff_oncellclick = function (rowIndex, columnIndex, columnId) {
    console.log("scwin.gr_tariff_oncellclick");

    switch (columnId) {
        case "aexpYn":
            if(ds_tariff.getCellData(rowIndex, "aexpYn") == "1") {
                gr_tariff.setReadOnly("cell", rowIndex, "ctrtTrf", true);
                ds_tariff.setCellData(rowIndex, "ctrtTrf", "0");
            } else {
                gr_tariff.setReadOnly("cell", rowIndex, "ctrtTrf", false);
            }
			break;

        case "eqKndCd":
			if(ds_tariff.getCellData(rowIndex, "eqKndCd") == "") {
				ds_tariff.setCellData(row, "minEqNrmCd", "");
				ds_tariff.setCellData(row, "maxEqNrmCd", "");
			} 
			break;

		default:
			break;
    }
};

//그리드에 바인딩 된 ds_tariff 값 Nm 변경 > 각 셀 cd 값 초기화 
scwin.ds_tariff_oncelldatachange = function (info) {
    console.log("scwin.ds_tariff_oncelldatachange");
    console.log(info);
    let columnId = info.colID;
    let rowIndex = info.rowIndex;

    switch (columnId) {
        case "commNm":
            if(ds_tariff.getCellData(rowIndex, columnId) == "" ) {
                ds_tariff.setCellData(rowIndex, "commCd", "");
            }   
            break;

        case "lobranNm":
            if(ds_tariff.getCellData(rowIndex, columnId) == "" ) {
                ds_tariff.setCellData(rowIndex, "lobranCd", "");
                gr_tariff.setReadOnly("cell", rowIndex, "lobranNm", false);
				gr_tariff.setReadOnly("cell", rowIndex, "portDistrictNm", false);
            } else {
                gr_tariff.setReadOnly("cell", rowIndex, "lobranNm", false);
				gr_tariff.setReadOnly("cell", rowIndex, "portDistrictNm", true);
            }
            break;

        case "eqKndCd":
            break;

		default:
			break;
	}
};

//그리드 수정 모드 종료 > 공통 코드 팝업 호출
scwin.gr_tariff_oneditend = function (rowIndex, columnIndex, value) {
    console.log(rowIndex, columnIndex, value);

    if(value == "")         return;
    scwin.f_openCommonPopUp(rowIndex, columnIndex, value);
};

//장비 종류에 따른 최소, 최대값 check 
scwin.ds_eqNrmCd_onrowpositionchange = function (info) {
    console.log(info.newRowIndex);
    var v_row = info.newRowIndex;

	if(ds_eqNrmCd.getTotalRow() > 0) {
		for(var i=0; i<ds_eqNrmCd.getTotalRow(); i++) {
			if(ds_tariff.getCellData(v_row, "minEqNrmCd") == ds_eqNrmCd.getCellData(i, "cd"))	
            break;
		}		

		if (i>ds_eqNrmCd.getTotalRow())	ds_tariff.setCellData(v_row, "minEqNrmCd", "");
	} else {
		ds_tariff.setCellData(v_row, "minEqNrmCd", "");
	}

	if(ds_eqNrmCd.getTotalRow > 0) {
		for(var i=0; i<ds_eqNrmCd.getTotalRow(); i++) {
			if(ds_tariff.getCellData(v_row, "maxEqNrmCd") == ds_eqNrmCd.getCellData(i, "cd"))	
            break;
		}	

		if (i>ds_eqNrmCd.getTotalRow())	ds_tariff.setCellData(v_row, "maxEqNrmCd", "");
	} else {
		ds_tariff.setCellData(v_row, "maxEqNrmCd", "");
	}
};

//저장 버튼
scwin.btn_save_onclick = function (e) {
    scwin.f_Save()
};

// 장비종류에 따른 장비규격(최소, 최대) 필터 시점 변경
scwin.gr_tariff_onbeforeedit = function (rowIndex, columnIndex, value) {
    const colid = gr_tariff.getColumnID(columnIndex);

    switch (colid) {
        case "minEqNrmCd":
        case "maxEqNrmCd":
            //차량종류 변경 > 규격 Filter
            if(ds_eqNrmCd.getTotalRow() == 0) return;

            scwin.f_filter();
        break;

        default:
        break;
    }

};

scwin.gr_tariff_onafteredit = function (rowIndex, columnIndex, value) {
    const colid = gr_tariff.getColumnID(columnIndex);

    switch (colid) {
        case "minEqNrmCd":
        case "maxEqNrmCd":
            ds_eqNrmCd.removeColumnFilterAll();
        break;

        default:
        break;
    }
};
